// src/lib/auth/paseto.ts
import { V4 } from 'paseto'
import { randomUUID } from 'crypto'
import { createPublicKey, createPrivateKey, KeyObject } from 'crypto'

const TOKEN_EXPIRY = '7d'
const COOKIE_MAX_AGE = 7 * 24 * 60 * 60

export interface TokenPayload {
  sub: string      // User ID
  role: string     // customer | owner | admin
  email: string    // User email
  jti?: string     // Unique token ID (auto-generated)
}

export interface DecodedToken extends TokenPayload {
  jti: string
  iat: string
  exp: string
}

function getPrivateKey(): KeyObject {
  const key = process.env.PASETO_PRIVATE_KEY
  if (!key) {
    throw new Error('PASETO_PRIVATE_KEY environment variable is not set')
  }
  const pem = `-----BEGIN PRIVATE KEY-----\n${key}\n-----END PRIVATE KEY-----`
  return createPrivateKey(pem)
}

function getPublicKey(): KeyObject {
  const key = process.env.PASETO_PUBLIC_KEY
  if (!key) {
    throw new Error('PASETO_PUBLIC_KEY environment variable is not set')
  }
  const pem = `-----BEGIN PUBLIC KEY-----\n${key}\n-----END PUBLIC KEY-----`
  return createPublicKey(pem)
}

export async function generateToken(payload: TokenPayload): Promise<string> {
  const key = getPrivateKey()
  const jti = payload.jti || randomUUID()

  const token = await V4.sign(
    {
      sub: payload.sub,
      role: payload.role,
      email: payload.email,
      jti,
      iat: new Date().toISOString()
    },
    key,
    {
      expiresIn: TOKEN_EXPIRY,
      issuer: 'desiremap.de',
      audience: 'desiremap.de'
    }
  )

  return token
}

export async function verifyToken(token: string): Promise<DecodedToken> {
  const key = getPublicKey()

  try {
    const payload = await V4.verify(token, key, {
      issuer: 'desiremap.de',
      audience: 'desiremap.de',
      clockTolerance: '1m'
    })

    return payload as unknown as DecodedToken
  } catch (error) {
    if (error instanceof Error) {
      if (error.message.includes('expired')) {
        throw new Error('Token expired')
      }
      if (error.message.includes('invalid')) {
        throw new Error('Invalid token')
      }
    }
    throw new Error('Token verification failed')
  }
}

export function extractToken(request: Request): string | null {
  // Check Authorization header first
  const authHeader = request.headers.get('authorization')
  if (authHeader?.startsWith('Bearer ')) {
    return authHeader.slice(7)
  }

  // Check cookie
  const cookie = request.headers.get('cookie')
  if (cookie) {
    const match = cookie.match(/auth_token=([^;]+)/)
    if (match) {
      return match[1]
    }
  }

  return null
}

export function getCookieOptions() {
  return {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict' as const,
    path: '/',
    maxAge: COOKIE_MAX_AGE
  }
}

// src/lib/auth/blacklist.ts

// In-memory blacklist for MVP
const blacklist = new Set<string>()

export function revokeToken(jti: string): void {
  blacklist.add(jti)
}

export function isRevoked(jti: string): boolean {
  return blacklist.has(jti)
}

export function cleanup(): void {
  // In production with Redis, this would be handled by TTL
  // For MVP, no-op
}

// src/lib/auth/guards.ts
import { NextRequest, NextResponse } from 'next/server'
import { verifyToken, extractToken, DecodedToken } from './paseto'
import { isRevoked } from './blacklist'

export interface AuthResult {
  success: true
  user: DecodedToken
}

export interface AuthError {
  success: false
  error: string
  status: number
}

export async function requireAuth(
  request: NextRequest
): Promise<AuthResult | AuthError> {
  const token = extractToken(request)

  if (!token) {
    return {
      success: false,
      error: 'Authentication required',
      status: 401
    }
  }

  try {
    const payload = await verifyToken(token)

    if (isRevoked(payload.jti)) {
      return {
        success: false,
        error: 'Token has been revoked',
        status: 401
      }
    }

    return {
      success: true,
      user: payload
    }
  } catch (error) {
    const message = error instanceof Error ? error.message : 'Invalid token'
    return {
      success: false,
      error: message,
      status: 401
    }
  }
}

export async function requireRole(
  request: NextRequest,
  allowedRoles: string[]
): Promise<AuthResult | AuthError> {
  const authResult = await requireAuth(request)

  if (!authResult.success) {
    return authResult
  }

  if (!allowedRoles.includes(authResult.user.role)) {
    return {
      success: false,
      error: 'Insufficient permissions',
      status: 403
    }
  }

  return authResult
}

export async function requireAdmin(
  request: NextRequest
): Promise<AuthResult | AuthError> {
  return requireRole(request, ['admin'])
}

export async function requireOwnerOrAdmin(
  request: NextRequest
): Promise<AuthResult | AuthError> {
  return requireRole(request, ['owner', 'admin'])
}

export function unauthorizedResponse(
  message = 'Authentication required'
): NextResponse {
  return NextResponse.json({ error: message }, { status: 401 })
}

export function forbiddenResponse(
  message = 'Insufficient permissions'
): NextResponse {
  return NextResponse.json({ error: message }, { status: 403 })
}

export function isOwner(userId: string, resourceUserId: string): boolean {
  return userId === resourceUserId
}

// src/lib/auth/password.ts
import bcrypt from 'bcryptjs'

const SALT_ROUNDS = 12

export async function hash(password: string): Promise<string> {
  if (!password || password.length < 8) {
    throw new Error('Password must be at least 8 characters')
  }
  if (password.length > 128) {
    throw new Error('Password must be at most 128 characters')
  }
  return bcrypt.hash(password, SALT_ROUNDS)
}

export async function verify(password: string, hash: string): Promise<boolean> {
  if (!password || !hash) {
    return false
  }
  return bcrypt.compare(password, hash)
}

export async function needsRehash(hash: string): Promise<boolean> {
  const rounds = bcrypt.getRounds(hash)
  return rounds < SALT_ROUNDS
}

// src/lib/auth/oauth/google.ts
import { randomUUID, randomBytes, createHash } from 'crypto'

export interface GoogleUser {
  id: string
  email: string
  emailVerified: boolean
  name?: string
  picture?: string
}

export interface OAuthState {
  state: string
  codeVerifier: string
  codeChallenge: string
}

function generateCodeVerifier(): string {
  return randomBytes(32)
    .toString('base64url')
    .slice(0, 43)
}

function generateCodeChallenge(verifier: string): string {
  return createHash('sha256')
    .update(verifier)
    .digest('base64url')
}

export function generateOAuthState(): OAuthState {
  const state = randomUUID()
  const codeVerifier = generateCodeVerifier()
  const codeChallenge = generateCodeChallenge(codeVerifier)

  return { state, codeVerifier, codeChallenge }
}

export function getAuthUrl(state: OAuthState): string {
  const clientId = process.env.GOOGLE_CLIENT_ID
  const redirectUri = process.env.GOOGLE_REDIRECT_URI

  if (!clientId || !redirectUri) {
    throw new Error('Google OAuth credentials not configured')
  }

  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: 'code',
    scope: 'openid email profile',
    state: state.state,
    code_challenge: state.codeChallenge,
    code_challenge_method: 'S256',
    access_type: 'offline',
    prompt: 'consent'
  })

  return `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`
}

export async function exchangeCode(
  code: string,
  codeVerifier: string
): Promise<{ accessToken: string; refreshToken?: string }> {
  const clientId = process.env.GOOGLE_CLIENT_ID
  const clientSecret = process.env.GOOGLE_CLIENT_SECRET
  const redirectUri = process.env.GOOGLE_REDIRECT_URI

  const response = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded'
    },
    body: new URLSearchParams({
      client_id: clientId!,
      client_secret: clientSecret!,
      code,
      code_verifier: codeVerifier,
      redirect_uri: redirectUri!,
      grant_type: 'authorization_code'
    }).toString()
  })

  const data = await response.json()
  return {
    accessToken: data.access_token,
    refreshToken: data.refresh_token
  }
}

export async function getUserInfo(accessToken: string): Promise<GoogleUser> {
  const response = await fetch('https://www.googleapis.com/oauth2/v3/userinfo', {
    headers: {
      Authorization: `Bearer ${accessToken}`
    }
  })

  const data = await response.json()
  return {
    id: data.sub,
    email: data.email,
    emailVerified: data.email_verified === true,
    name: data.name,
    picture: data.picture
  }
}

