export async function POST(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions)

    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const body = await request.json()
    const { bordellId, date, time, duration, price, notes } = body

    if (!bordellId || !date || !time || !duration || !price) {
      return NextResponse.json(
        { error: 'Missing required fields' },
        { status: 400 }
      )
    }

    // Verify bordell exists and is active
    const bordell = await db.bordell.findUnique({
      where: { id: bordellId }
    })

    if (!bordell || bordell.status !== 'ACTIVE') {
      return NextResponse.json(
        { error: 'Establishment not available' },
        { status: 400 }
      )
    }

    const booking = await db.booking.create({
      data: {
        customerId: session.user.id,
        bordellId,
        date: new Date(date),
        time,
        duration,
        price,
        notes: notes || null,
        status: 'PENDING',
        paymentStatus: 'PENDING'
      },
      include: {
        bordell: { select: { name: true } }
      }
    })

    // Update bordell booking count
    await db.bordell.update({
      where: { id: bordellId },
      data: { bookings: { increment: 1 } }
    })

    return NextResponse.json({
      id: booking.id,
      bordellId: booking.bordellId,
      bordellName: booking.bordell.name,
      date: booking.date.toISOString(),
      time: booking.time,
      duration: booking.duration,
      price: booking.price,
      status: booking.status.toLowerCase(),
      paymentStatus: booking.paymentStatus.toLowerCase(),
      createdAt: booking.createdAt.toISOString()
    }, { status: 201 })
  } catch (error) {
    console.error('Create booking error:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function GET(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await getServerSession(authOptions)
  const { id } = await params

  const booking = await db.booking.findUnique({
    where: { id },
    include: {
      customer: { select: { id: true, name: true, email: true } },
      bordell: { select: { id: true, name: true } }
    }
  })

  if (!booking) {
    return NextResponse.json({ error: 'Booking not found' }, { status: 404 })
  }

  const isAdmin = session.user.role === 'admin'
  const isOwner = booking.customerId === session.user.id

  if (!isAdmin && !isOwner) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 })
  }

  return NextResponse.json({ /* booking data */ })
}

export async function DELETE(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const session = await getServerSession(authOptions)
  const { id } = await params

  const booking = await db.booking.findUnique({ where: { id } })

  if (!booking) {
    return NextResponse.json({ error: 'Booking not found' }, { status: 404 })
  }

  const isAdmin = session.user.role === 'admin'
  const isOwner = booking.customerId === session.user.id

  if (!isAdmin && !isOwner) {
    return NextResponse.json({ error: 'Forbidden' }, { status: 403 })
  }

  // Only allow cancellation if pending
  if (booking.status !== 'PENDING' && !isAdmin) {
    return NextResponse.json(
      { error: 'Cannot cancel this booking' },
      { status: 400 }
    )
  }

  await db.booking.update({
    where: { id },
    data: { status: 'CANCELLED' }
  })

  return NextResponse.json({ success: true })
}

export async function GET() {
  try {
    const session = await checkAdminAccess()
    if (!session) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    // Parallel count queries for performance
    const [
      totalEstablishments,
      activeEstablishments,
      pendingEstablishments,
      totalCustomers,
      activeCustomers,
      totalBookings,
      pendingBookings,
      completedBookings,
      totalReviews,
      pendingReviews
    ] = await Promise.all([
      db.bordell.count(),
      db.bordell.count({ where: { status: 'ACTIVE' } }),
      db.bordell.count({ where: { status: 'PENDING' } }),
      db.user.count({ where: { role: 'CUSTOMER' } }),
      db.user.count({ where: { role: 'CUSTOMER', status: 'ACTIVE' } }),
      db.booking.count(),
      db.booking.count({ where: { status: 'PENDING' } }),
      db.booking.count({ where: { status: 'COMPLETED' } }),
      db.review.count(),
      db.review.count({ where: { status: 'PENDING' } })
    ])

    // Calculate revenue from completed + paid bookings
    const completedBookingsData = await db.booking.findMany({
      where: { status: 'COMPLETED', paymentStatus: 'PAID' },
      select: { price: true }
    })
    const totalRevenue = completedBookingsData.reduce((sum, b) => sum + b.price, 0)

    // Monthly stats (last 6 months)
    const sixMonthsAgo = new Date()
    sixMonthsAgo.setMonth(sixMonthsAgo.getMonth() - 6)

    const recentBookings = await db.booking.findMany({
      where: { createdAt: { gte: sixMonthsAgo } },
      select: { price: true, createdAt: true, status: true }
    })

    const monthlyStats: { [key: string]: { bookings: number; revenue: number } } = {}
    recentBookings.forEach(b => {
      const month = b.createdAt.toISOString().slice(0, 7)
      if (!monthlyStats[month]) {
        monthlyStats[month] = { bookings: 0, revenue: 0 }
      }
      monthlyStats[month].bookings++
      if (b.status === 'COMPLETED') {
        monthlyStats[month].revenue += b.price
      }
    })

    // Top establishments
    const topEstablishments = await db.bordell.findMany({
      where: { status: 'ACTIVE' },
      orderBy: { bookings: 'desc' },
      take: 5,
      select: { id: true, name: true, city: true, bookings: true, revenue: true }
    })

    return NextResponse.json({
      overview: {
        totalEstablishments,
        activeEstablishments,
        pendingEstablishments,
        totalCustomers,
        activeCustomers,
        totalBookings,
        pendingBookings,
        completedBookings,
        totalReviews,
        pendingReviews,
        totalRevenue
      },
      monthlyStats: Object.entries(monthlyStats).map(([month, data]) => ({
        month,
        bookings: data.bookings,
        revenue: data.revenue
      })),
      topEstablishments
    })
  } catch (error) {
    console.error('Get admin stats error:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const query = searchParams.get('q') || ''
    const city = searchParams.get('city') || ''
    const type = searchParams.get('type') || ''
    const minPrice = searchParams.get('minPrice')
    const maxPrice = searchParams.get('maxPrice')
    const limit = parseInt(searchParams.get('limit') || '20')
    const offset = parseInt(searchParams.get('offset') || '0')

    const where: any = { status: 'ACTIVE' }

    if (query) {
      where.OR = [
        { name: { contains: query } },
        { description: { contains: query } },
        { location: { contains: query } }
      ]
    }

    if (city) {
      where.city = { contains: city }
    }

    if (type) {
      where.type = type.toUpperCase()
    }

    if (minPrice || maxPrice) {
      where.minPrice = {}
      if (minPrice) where.minPrice.gte = parseFloat(minPrice)
      if (maxPrice) where.minPrice.lte = parseFloat(maxPrice)
    }

    const [establishments, total] = await Promise.all([
      db.bordell.findMany({
        where,
        take: limit,
        skip: offset,
        orderBy: [
          { sponsored: 'desc' },
          { premium: 'desc' },
          { rating: 'desc' }
        ]
      }),
      db.bordell.count({ where })
    ])

    return NextResponse.json({
      results: establishments.map(e => ({
        id: e.id,
        name: e.name,
        type: e.type.toLowerCase(),
        city: e.city,
        rating: e.rating,
        reviewCount: e.reviewCount,
        minPrice: e.minPrice,
        maxPrice: e.maxPrice,
        services: e.services ? JSON.parse(e.services) : [],
        images: e.images ? JSON.parse(e.images) : [],
        verified: e.verified,
        premium: e.premium,
        sponsored: e.sponsored
      })),
      total,
      limit,
      offset
    })
  } catch (error) {
    console.error('Search establishments error:', error)
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 })
  }
}

export async function PUT(request: NextRequest) {
  const body = await request.json()
  const { id, status, response } = body

  const data: any = {}
  if (status) data.status = status.toUpperCase()
  if (response !== undefined) {
    data.response = response
    data.respondedAt = new Date()
  }

  const review = await db.review.update({
    where: { id },
    data
  })

  // If approved, recalculate bordell rating
  if (status === 'APPROVED') {
    const bordellReviews = await db.review.findMany({
      where: { bordellId: review.bordellId, status: 'APPROVED' },
      select: { rating: true }
    })

    if (bordellReviews.length > 0) {
      const avgRating = bordellReviews.reduce((sum, r) => sum + r.rating, 0) 
                        / bordellReviews.length
      await db.bordell.update({
        where: { id: review.bordellId },
        data: {
          rating: Math.round(avgRating * 10) / 10,
          reviewCount: bordellReviews.length
        }
      })
    }
  }

  return NextResponse.json({
    id: review.id,
    status: review.status.toLowerCase()
  })
}

