// src/middleware.ts
import { NextRequest, NextResponse } from 'next/server'
import { verifyToken } from './lib/auth/paseto'
import { isRevoked } from './lib/auth/blacklist'

const protectedRoutes = {
  admin: {
    paths: ['/de/admin', '/en/admin', '/tr/admin', '/ar/admin'],
    roles: ['admin']
  },
  dashboard: {
    paths: ['/de/dashboard', '/en/dashboard', '/tr/dashboard', '/ar/dashboard'],
    roles: ['customer', 'owner', 'admin']
  },
  owner: {
    paths: ['/de/owner', '/en/owner', '/tr/owner', '/ar/owner'],
    roles: ['owner', 'admin']
  }
}

const authRoutes = [
  '/de/login', '/en/login', '/tr/login', '/ar/login',
  '/de/register', '/en/register', '/tr/register', '/ar/register'
]

export async function middleware(request: NextRequest) {
  const { pathname } = request.nextUrl
  const token = request.cookies.get('auth_token')?.value

  // Redirect authenticated users away from auth pages
  const isAuthRoute = authRoutes.some(route => pathname.startsWith(route))
  if (token && isAuthRoute) {
    try {
      const payload = await verifyToken(token)
      if (!isRevoked(payload.jti)) {
        const locale = pathname.split('/')[1] || 'de'
        return NextResponse.redirect(new URL(`/${locale}/dashboard`, request.url))
      }
    } catch { /* invalid token, proceed */ }
  }

  // Check route protection
  let requiredRoles: string[] | null = null
  for (const [, config] of Object.entries(protectedRoutes)) {
    if (config.paths.some(path => pathname.startsWith(path))) {
      requiredRoles = config.roles
      break
    }
  }

  if (!requiredRoles) {
    return NextResponse.next()
  }

  // No token - redirect to login
  if (!token) {
    const locale = pathname.split('/')[1] || 'de'
    const loginUrl = new URL(`/${locale}/login`, request.url)
    loginUrl.searchParams.set('redirect', pathname)
    return NextResponse.redirect(loginUrl)
  }

  // Verify token
  let payload
  try {
    payload = await verifyToken(token)
  } catch {
    const locale = pathname.split('/')[1] || 'de'
    const loginUrl = new URL(`/${locale}/login`, request.url)
    loginUrl.searchParams.set('error', 'session_expired')
    return NextResponse.redirect(loginUrl)
  }

  // Check revocation
  if (isRevoked(payload.jti)) {
    const locale = pathname.split('/')[1] || 'de'
    const loginUrl = new URL(`/${locale}/login`, request.url)
    loginUrl.searchParams.set('error', 'session_revoked')
    return NextResponse.redirect(loginUrl)
  }

  // Check role
  if (!requiredRoles.includes(payload.role)) {
    const locale = pathname.split('/')[1] || 'de'
    return NextResponse.redirect(new URL(`/${locale}?error=unauthorized`, request.url))
  }

  // Set user headers for API routes
  const response = NextResponse.next()
  response.headers.set('x-user-id', payload.sub)
  response.headers.set('x-user-role', payload.role)
  response.headers.set('x-user-email', payload.email)

  return response
}

export const config = {
  matcher: [
    '/((?!api|_next/static|_next/image|favicon.ico|icon.svg|images|covers|.*\\.(?:jpg|jpeg|png|webp|svg|gif|ico|woff|woff2)).*)'
  ]
}

// src/lib/seedData.ts
import { db } from './db'
import bcrypt from 'bcryptjs'

export async function seedDatabase() {
  // Clear existing data
  await db.invoice.deleteMany()
  await db.review.deleteMany()
  await db.booking.deleteMany()
  await db.visit.deleteMany()
  await db.userBadge.deleteMany()
  await db.address.deleteMany()
  await db.bordell.deleteMany()
  await db.badge.deleteMany()
  await db.user.deleteMany()

  // Create badges
  const badges = await Promise.all([
    db.badge.create({
      data: { name: 'Premium', description: 'Premium üyelik', icon: 'crown', color: '#FFD700' }
    }),
    db.badge.create({
      data: { name: 'Early Adopter', description: 'İlk kullanıcılar', icon: 'star', color: '#4CAF50' }
    }),
    db.badge.create({
      data: { name: 'Active Member', description: 'Aktif üye', icon: 'zap', color: '#2196F3' }
    }),
    db.badge.create({
      data: { name: 'Top Reviewer', description: 'En çok yorum', icon: 'message-circle', color: '#9C27B0' }
    })
  ])

  // Create admin
  const admin = await db.user.create({
    data: {
      email: 'admin@desiremap.de',
      password: await bcrypt.hash('admin123', 12),
      name: 'Admin User',
      role: 'ADMIN',
      status: 'ACTIVE'
    }
  })

  // Create customers
  const customers = await Promise.all([
    db.user.create({
      data: {
        email: 'max@example.com',
        password: await bcrypt.hash('password123', 12),
        name: 'Max Mustermann',
        role: 'CUSTOMER',
        status: 'ACTIVE'
      }
    }),
    // ... more customers
  ])

  return { badges, admin, customers }
}

